import ccxt.async_support as ccxt  # noqa: F402

def test_urlencode_with_array_repeat():
    exchange = ccxt.Exchange({
        'id': 'sampleexchange',
    })
    dict2 = {
        'a': 1,
        'product_ids': ['AA', 'BB'],
    }
    expected2a = 'a=1&product_ids=AA&product_ids=BB'
    expected2b = 'product_ids=AA&product_ids=BB&a=1'
    result2 = exchange.urlencode_with_array_repeat(dict2)
    assert result2 == expected2a or result2 == expected2b, 'urlencodeWithArrayRepeat: expected ' + expected2a + ' or ' + expected2b + ' but got ' + result2
